"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { FileUp, FileDown, Loader2 } from "lucide-react";

export default function CompressPage() {
  const [file, setFile] = useState<File | null>(null);
  const [algorithm, setAlgorithm] = useState("huffman");
  const [loading, setLoading] = useState(false);
  const [htmlResult, setHtmlResult] = useState("");

  async function handleCompress() {
    if (!file) return;

    setLoading(true);

    const formData = new FormData();
    formData.append("file", file);
    formData.append("algorithm", algorithm);

    const res = await fetch("http://127.0.0.1:8000/compress", {
      method: "POST",
      body: formData,
    });

    const text = await res.text();
    setHtmlResult(text);
    setLoading(false);
  }

  return (
    <div className="text-white">
      <motion.h1
        className="text-4xl font-bold mb-8"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
      >
        Compression de Fichier
      </motion.h1>

      <div className="bg-white/10 p-8 rounded-2xl backdrop-blur-xl w-[600px]">

        {/* File Upload */}
        <label className="flex items-center gap-4 cursor-pointer p-4 border border-white/20 rounded-xl hover:bg-white/10 transition">
          <FileUp size={28} />
          <input
            type="file"
            className="hidden"
            onChange={(e) => setFile(e.target.files?.[0] || null)}
          />
          {file ? file.name : "Choisir un fichier"}
        </label>

        {/* Algorithm */}
        <select
          className="w-full mt-6 p-3 rounded-xl bg-white/20 border border-white/30"
          value={algorithm}
          onChange={(e) => setAlgorithm(e.target.value)}
        >
          <option value="huffman">Huffman</option>
          <option value="lzw">LZW</option>
          <option value="rle">RLE</option>
        </select>

        {/* Compress Button */}
        <button
          onClick={handleCompress}
          disabled={loading || !file}
          className="mt-6 w-full bg-white text-black py-3 rounded-xl font-semibold hover:scale-[1.03] transition flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? (
            <>
              <Loader2 className="animate-spin" size={22} />
              Compression en cours...
            </>
          ) : (
            <>
              <FileDown size={22} />
              Compresser
            </>
          )}
        </button>
      </div>

      {/* Result */}
      {htmlResult && (
        <div className="mt-10 bg-white/10 p-6 rounded-xl backdrop-blur-xl">
          <h2 className="text-2xl font-bold mb-4">Résultat :</h2>

          <div
            className="bg-black/40 p-4 rounded-xl"
            dangerouslySetInnerHTML={{ __html: htmlResult }}
          />
        </div>
      )}
    </div>
  );
}

